(function($){$(function(){var $sel=$("#fq_rutina_productos");if(!$sel.length||typeof $.fn.select2!=="function"){return}var restUrl=$sel.data("rest-url");var restNonce=$sel.data("rest-nonce");var placeholder=$sel.data("placeholder")||"Busca productos...";$sel.select2({width:"100%",placeholder:placeholder,allowClear:true,ajax:{url:restUrl,dataType:"json",delay:250,headers:{"X-WP-Nonce":restNonce},data:function(p){return{search:p.term||"",page:p.page||1}},processResults:function(d){return{results:d.results||[],pagination:d.pagination||{more:false}}},cache:true},minimumInputLength:0,language:{noResults:function(){return"Sin resultados"},searching:function(){return"Buscando..."},loadingMore:function(){return"Cargando más resultados..."}}});})})(jQuery);
